using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int k[MAXN],p[MAXN],n,m,mid,ans=0;
map<int,int> cnt1;
int qpow(int y,int x)//quick pow (here not x,y)
{
	int ans=1;
	wh(x)
	{
		if(x%2)ans*=y;
		x/=2;
		y=y*y;
	}
	return ans;
} 
void dfs(int num,int sum)//dfs(left)
{
	if(num>mid)
	{
		++cnt1[-sum];//-sum because left_sum+right_sum=0
		return;
	}
	FOR(i,1,m)
	{
		dfs(num+1,sum+k[num]*qpow(i,p[num]));
	}
}
void dfs2(int num,int sum)//dfs(right)
{
	if(num>n)
	{
		ans+=cnt1[sum];
		return;
	}
	FOR(i,1,m)
	{
		dfs2(num+1,sum+k[num]*qpow(i,p[num]));
	}
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	n=read(),m=read();
	mid=n/2;
	FOR(i,1,n)
	{
		k[i]=read(),p[i]=read(); 
	}
	dfs(1,0);
	dfs2(mid+1,0);
	cout<<ans;
    return false;
}
